script:
frappe.ui.form.on('Customer Visit', {

    checkout_time: function(frm) {

        if (frm.doc.checkin_time && frm.doc.checkout_time) {

            let checkin = new Date(frm.doc.checkin_time);
            let checkout = new Date(frm.doc.checkout_time);

            let diff = (checkout - checkin) / (1000 * 60 * 60);

            frm.set_value('visit_duration', diff);

        }

    }

});
